INSERT INTO "games" ("id","title","released","companie","poster","trailer","artworks","genre","estado","logros_obt","logros_total","console_pc","igdb_id","first_year_played","description","created_at","updated_at","rating_metacritic","rating_rawg","is_demo","is_early_access") VALUES(4,'Bright Memory','24/03/2020','FYQD-Studio','co26z5.webp','s73I1DaHnqM','ar11k3.webp','Shooter, Adventure, Indie','Completado',5,12,'Steam',134072,2025,'Bright Memory es una fusión vertiginosa de los géneros FPS y acción, creada por el estudio de desarrollo independiente FYQD utilizando Unreal Engine. Combina una amplia variedad de habilidades y destrezas para desatar deslumbrantes ataques combinados. La aventura de Shelia, agente de la SRO (Organización de Investigación Científica Sobrenatural), está a punto de comenzar.','2026-03-18 16:13:20','2026-03-18 16:13:20',55,3.51,0,0);
INSERT INTO "games" ("id","title","released","companie","poster","trailer","artworks","genre","estado","logros_obt","logros_total","console_pc","igdb_id","first_year_played","description","created_at","updated_at","rating_metacritic","rating_rawg","is_demo","is_early_access") VALUES(5,'Call of Duty® (2003)','29/10/2003','Infinity Ward','co2n19.png','YUrUDrjOFYY','arejd.webp','Shooter','Completado',0,0,'Steam',621,2024,'«Call of Duty» (2003) es el juego inaugural de la aclamada serie de shooters en primera persona desarrollada por Infinity Ward y publicada por Activision. Ambientado en la Segunda Guerra Mundial, ofrece una experiencia intensa y cinematográfica que lleva a los jugadores a través de batallas clave en el Teatro de Operaciones Europeo. El juego incluye tres campañas entrelazadas que permiten a los jugadores luchar como soldados estadounidenses, británicos y soviéticos.','2026-03-18 16:13:20','2026-03-18 16:13:20',91,4.16,0,0);
INSERT INTO "games" ("id","title","released","companie","poster","trailer","artworks","genre","estado","logros_obt","logros_total","console_pc","igdb_id","first_year_played","description","created_at","updated_at","rating_metacritic","rating_rawg","is_demo","is_early_access") VALUES(6,'Call of Duty® 2','25/10/2005','Infinity Ward','co3acf.png','XexzQKXGQrk','ar798.webp','Shooter','Completado',0,0,'Steam',622,2024,'«Call of Duty 2» es un juego de disparos en primera persona desarrollado por Infinity Ward y publicado por Activision, que constituye la aclamada secuela del "Call of Duty" original. Lanzado en 2005, el juego sumerge a los jugadores en las apasionantes y caóticas batallas de la Segunda Guerra Mundial en varios teatros de guerra.','2026-03-18 16:13:20','2026-03-18 16:13:20',86,4.21,0,0);
INSERT INTO "games" ("id","title","released","companie","poster","trailer","artworks","genre","estado","logros_obt","logros_total","console_pc","igdb_id","first_year_played","description","created_at","updated_at","rating_metacritic","rating_rawg","is_demo","is_early_access") VALUES(7,'Call of Duty® 4: Modern Warfare® (2007)','05/11/2007','Treyarch','co1wko.png','8e-i2D-2GAc','ar79g.webp','Shooter, Simulator','Completado',0,0,'Steam',623,2024,'Call of Duty 4: Modern Warfare difiere de las anteriores entregas de la serie Call of Duty. Los anteriores juegos de Call of Duty tenían un estilo de campaña específico para tres países, mientras que Call of Duty 4 tiene una trama más cinematográfica, con historias entrelazadas desde las perspectivas del sargento Paul Jackson, de la 1st Force Recon de los Marines, y del sargento ''Soap'' MacTavish, del 22º Regimiento SAS británico.','2026-03-18 16:13:20','2026-03-18 16:13:20',92,4.39,0,0);
