INSERT INTO "games" ("id","title","released","companie","poster","trailer","artworks","genre","estado","logros_obt","logros_total","console_pc","igdb_id","first_year_played","description","created_at","updated_at","rating_metacritic","rating_rawg","is_demo","is_early_access") VALUES(12,'Darksiders Genesis','01/12/2019','Airship Syndicate','co1n1f.webp','lcEW7_dr7mc','ar7wx.webp','Role-playing (RPG), Hack and slash/Beat ''em up, Adventure','Completado',8,30,'Steam',119244,2025,'En este spin-off de rol y acción, el cuarto Jinete del Apocalipsis, Strife, es llamado a salvar a la humanidad de la destrucción a manos de Lucifer. Fiel a sus raíces, Darksiders Genesis ofrecerá intensos combates, exploración, resolución de puzles, épicas batallas contra jefes y los túneles de la serpiente que conectan el cielo con el infierno. El juego supone la primera aventura completa de Darksiders con perspectiva cenital.','2026-03-18 16:13:20','2026-03-18 16:13:20',76,3.58,0,0);
