INSERT INTO "games" ("id","title","released","companie","poster","trailer","artworks","genre","estado","logros_obt","logros_total","console_pc","igdb_id","first_year_played","description","created_at","updated_at","rating_metacritic","rating_rawg","is_demo","is_early_access") VALUES(55,'Windrose','','Windrose Crew','coay9m.webp','EDnFI1SLMLo','ar4uzq.webp','Role-playing (RPG), Adventure','Completado',0,0,'Steam',380441,2026,'Windrose es una aventura de supervivencia ambientada en la era de la piratería. Explora un mundo abierto procedural, recolecta, construye y crea objetos. Derrota a jefes desafiantes en combates al estilo Souls. Navega con tu barco, lucha en tierra y mar, juega solo o con amigos.','2026-03-18 16:13:20','2026-03-21 19:23:22',NULL,NULL,0,0);
INSERT INTO "games" ("id","title","released","companie","poster","trailer","artworks","genre","estado","logros_obt","logros_total","console_pc","igdb_id","first_year_played","description","created_at","updated_at","rating_metacritic","rating_rawg","is_demo","is_early_access") VALUES(56,'World of Goo','03/04/2013','2D Boy','co24jz.webp','92rWWaspoFI','arcrb.webp','Puzzle, Simulator, Strategy, Indie','Completado',1,8,'Steam',942,2025,'World of Goo es un juego de construcción y rompecabezas basado en la física, ganador de múltiples premios, creado íntegramente por dos personas. Arrastra y suelta bolas de sustancia viscosa vivientes, retorcidas y parlantes para construir estructuras, puentes, balas de cañón, zepelines y lenguas gigantes.','2026-03-18 16:13:20','2026-03-18 16:13:20',90,4.02,0,0);
INSERT INTO "games" ("id","title","released","companie","poster","trailer","artworks","genre","estado","logros_obt","logros_total","console_pc","igdb_id","first_year_played","description","created_at","updated_at","rating_metacritic","rating_rawg","is_demo","is_early_access") VALUES(57,'Cuphead','28/09/2017','Studio MDHR','co62ao.webp','D-1n15aIgsE','ec5tsfhl7wjabwjnsshs.webp','Shooter, Platform, Adventure, Indie, Arcade','Completado',26,42,'Steam',9061,2026,'Cuphead es un clásico juego de acción del tipo «correr y disparar» que se centra principalmente en las batallas contra jefes. Inspirado en los dibujos animados de la década de 1930, los gráficos y el audio se han creado minuciosamente con las mismas técnicas de la época, es decir, animación tradicional en cel (¡dibujada y entintada a mano!), fondos en acuarela y grabaciones originales de jazz. Juega como Cuphead o Mugman (en modo individual o cooperativo) mientras recorres mundos extraños, consigues nuevas armas, aprendes poderosos supermovimientos y descubres secretos ocultos. Cuphead es pura acción, todo el tiempo. Sin pausas para recargar, sin regeneración de salud y sin vidas extra. Solo tú, tu ingenio y tus reflejos para superar cada desafío.','2026-03-18 16:13:20','2026-03-18 19:23:28',87,4.37,0,0);
INSERT INTO "games" ("id","title","released","companie","poster","trailer","artworks","genre","estado","logros_obt","logros_total","console_pc","igdb_id","first_year_played","description","created_at","updated_at","rating_metacritic","rating_rawg","is_demo","is_early_access") VALUES(58,'Wuthering Waves','2024','Kuro Games','cob4qg.webp','R8htow_6tRc','ar1nwd.webp','Role-playing (RPG), Adventure','Jugando',0,0,'Steam',202956,2026,'Wuthering Waves es un juego de rol de acción de mundo abierto con una historia muy rica. Despertarás de tu letargo en la piel de Rover y, junto a un variopinto elenco de Resonadores, emprenderás un viaje para recuperar tus recuerdos perdidos y superar el Lamento. El juego ofrece combates trepidantes con una variedad de mecánicas, como la «Evasión extrema» y el «Contraataque tras esquivar». También podrás absorber los restos de los monstruos que hayas derrotado y utilizar su poder en las batallas.','2026-03-20 12:12:05','2026-04-04 11:40:04',71,3.4,0,0);
