INSERT INTO "movies_cache" ("trakt_id","tmdb_id","imdb_id","title","year","released","runtime","genres","overview","rating","poster","thumb","list_slug","list_order","listed_at","tagline","certification","country","language","trailer","homepage","fanart","logo","cast_json","videos_json","images_json","after_credits","during_credits","votes","detail_fetched_at","updated_at") VALUES(610,767,'tt0417741','Harry Potter and the Half-Blood Prince',2009,'2009-07-15',153,'adventure, fantasy','As Lord Voldemort tightens his grip on both the Muggle and wizarding worlds, Hogwarts is no longer a safe haven. Harry suspects perils may even lie within the castle, but Dumbledore is more intent upon preparing him for the final battle fast approaching. Together they work to find the key to unlock Voldemorts defenses and to this end, Dumbledore recruits his old friend and colleague Horace Slughorn, whom he believes holds crucial information. Even as the decisive showdown looms, romance blossoms for Harry, Ron, Hermione and their classmates. Love is in the air, but danger lies ahead and Hogwarts may never be the same again.',7.9,'https://media.trakt.tv/images/movies/000/000/610/posters/medium/9d1a0c8829.jpg.webp','https://media.trakt.tv/images/movies/000/000/610/fanarts/medium/2a0cf7dc11.jpg.webp','movies-2023',80,'2023-02-11T11:55:05.000Z',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,'2026-04-04 11:57:05');
