INSERT INTO "movies_cache" ("trakt_id","tmdb_id","imdb_id","title","year","released","runtime","genres","overview","rating","poster","thumb","list_slug","list_order","listed_at","tagline","certification","country","language","trailer","homepage","fanart","logo","cast_json","videos_json","images_json","after_credits","during_credits","votes","detail_fetched_at","updated_at") VALUES(3752,6877,'tt0427229','Failure to Launch',2006,'2006-03-10',97,'comedy, romance','At 35, Tripp has an interesting job, a hip car, a passion for sailing, an active dating life, and a great house - trouble is, he still lives with his parents, Al and Sue, who are not happy about it. Al and Sue are fascinated when friends whose adult son has recently moved away from home reveal they hired an expert to help. In desperation to push Tripp out of the nest once and for all, Al and Sue hatch a plan to hire Paula, an "interventionist," who has a formula in these cases.',6.1,'https://media.trakt.tv/images/movies/000/003/752/posters/medium/bdcc4d2021.jpg.webp','https://media.trakt.tv/images/movies/000/003/752/fanarts/medium/95d4ce65ab.jpg.webp','movies-2025',51,'2025-01-18T18:39:12.000Z',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,'2026-04-04 12:02:48');
