INSERT INTO "movies_cache" ("trakt_id","tmdb_id","imdb_id","title","year","released","runtime","genres","overview","rating","poster","thumb","list_slug","list_order","listed_at","tagline","certification","country","language","trailer","homepage","fanart","logo","cast_json","videos_json","images_json","after_credits","during_credits","votes","detail_fetched_at","updated_at") VALUES(3925,7485,'tt0822854','Shooter',2007,'2007-03-22',124,'action, drama, thriller','A top Marine sniper, Bob Lee Swagger, leaves the military after a mission goes horribly awry and disappears, living in seclusion. He is coaxed back into service after a high-profile government official convinces him to help thwart a plot to kill the President of the United States. Ultimately double-crossed and framed for the attempt, Swagger becomes the target of a nationwide manhunt. He goes on the run to track the real killer and find out who exactly set him up, and why, eventually seeking revenge against some of the most powerful and corrupt leaders in the free world.',7.4,'https://media.trakt.tv/images/movies/000/003/925/posters/medium/65d0327615.jpg.webp','https://media.trakt.tv/images/movies/000/003/925/fanarts/medium/c537926b94.jpg.webp','movies-2018',31,'2018-03-30T13:11:27.000Z',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,'2026-04-04 11:45:50');
