INSERT INTO "movies_cache" ("trakt_id","tmdb_id","imdb_id","title","year","released","runtime","genres","overview","rating","poster","thumb","list_slug","list_order","listed_at","tagline","certification","country","language","trailer","homepage","fanart","logo","cast_json","videos_json","images_json","after_credits","during_credits","votes","detail_fetched_at","updated_at") VALUES(998800,1234821,'tt31036941','Jurassic World Rebirth',2025,'2025-07-02',134,'science-fiction, adventure, action','Five years after the events of Jurassic World Dominion, covert operations expert Zora Bennett is contracted to lead a skilled team on a top-secret mission to secure genetic material from the world''s three most massive dinosaurs. When Zora''s operation intersects with a civilian family whose boating expedition was capsized, they all find themselves stranded on an island where they come face-to-face with a sinister, shocking discovery that''s been hidden from the world for decades.',6.3,'https://media.trakt.tv/images/movies/000/998/800/posters/medium/9672be302b.jpg.webp','https://media.trakt.tv/images/movies/000/998/800/fanarts/medium/66a0fe6e49.jpg.webp','movies-2026',9,'2026-02-25T23:41:38.000Z',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,'2026-04-04 12:03:27');
