INSERT INTO "movies_cache" ("trakt_id","tmdb_id","imdb_id","title","year","released","runtime","genres","overview","rating","poster","thumb","list_slug","list_order","listed_at","tagline","certification","country","language","trailer","homepage","fanart","logo","cast_json","videos_json","images_json","after_credits","during_credits","votes","detail_fetched_at","updated_at") VALUES(1112909,1363123,'tt34276058','The Family Plan 2',2025,'2025-11-20',106,'action, comedy','Now that Dan''s assassin days are behind him, all he wants for Christmas is quality time with his kids. But when he learns his daughter has her own plans, he books a family trip to London—putting them all in the crosshairs of an unexpected enemy.',6.5,'https://media.trakt.tv/images/movies/001/112/909/posters/medium/ec87a5d865.jpg.webp','https://media.trakt.tv/images/movies/001/112/909/fanarts/medium/28501bdeb6.jpg.webp','movies-2025',24,'2025-12-22T23:50:36.000Z',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,'2026-04-04 12:01:45');
