PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE games (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  title TEXT NOT NULL,
  released TEXT,
  companie TEXT,
  poster TEXT,
  trailer TEXT,
  artworks TEXT,
  genre TEXT,
  estado TEXT NOT NULL DEFAULT 'Jugando',
  logros_obt INTEGER DEFAULT 0,
  logros_total INTEGER DEFAULT 0,
  console_pc TEXT,
  igdb_id INTEGER,
  first_year_played INTEGER,
  description TEXT,
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
, rating_metacritic INTEGER DEFAULT NULL, rating_rawg REAL DEFAULT NULL, is_demo INTEGER DEFAULT 0, is_early_access INTEGER DEFAULT 0);
CREATE TABLE dates_played (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  game_id INTEGER NOT NULL,
  year INTEGER NOT NULL,
  fecha_inicio TEXT,
  fecha_final TEXT,
  horas REAL DEFAULT 0,
  FOREIGN KEY (game_id) REFERENCES games(id) ON DELETE CASCADE
);
CREATE TABLE steam_cache (appid INTEGER PRIMARY KEY, name TEXT NOT NULL, developer TEXT, publisher TEXT, genres TEXT, released TEXT, poster TEXT, playtime INTEGER DEFAULT 0, last_played INTEGER DEFAULT 0, hltb_main REAL, hltb_extra REAL, hltb_completionist REAL, updated_at TEXT DEFAULT (datetime('now')));
CREATE TABLE next_games_featured (igdb_id INTEGER PRIMARY KEY, created_at TEXT DEFAULT (datetime('now')));
CREATE TABLE next_games_cache (igdb_id INTEGER PRIMARY KEY, name TEXT NOT NULL, developer TEXT, publisher TEXT, genres TEXT, cover TEXT, bg_image TEXT, release_date INTEGER DEFAULT 0, platforms TEXT, steam_url TEXT, hypes INTEGER DEFAULT 0, follows INTEGER DEFAULT 0, updated_at TEXT DEFAULT (datetime('now')));
CREATE TABLE movies_lists (
  slug TEXT PRIMARY KEY,
  description TEXT,
  item_count INTEGER DEFAULT 0,
  updated_at TEXT DEFAULT (datetime('now'))
);
CREATE TABLE series_watched (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  trakt_slug TEXT NOT NULL,
  season_number INTEGER NOT NULL,
  year_watched INTEGER NOT NULL,
  platform TEXT,
  status_viewed TEXT DEFAULT 'completed',
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now')),
  UNIQUE(trakt_slug, season_number)
);
CREATE TABLE series_cache (trakt_slug TEXT PRIMARY KEY, trakt_id INTEGER, tmdb_id INTEGER, imdb_id TEXT, title TEXT NOT NULL, year INTEGER, overview TEXT, rating REAL DEFAULT 0, genres TEXT, network TEXT, status TEXT, runtime INTEGER DEFAULT 0, poster TEXT, thumb TEXT, tagline TEXT, certification TEXT, country TEXT, language TEXT, trailer TEXT, fanart TEXT, logo TEXT, airs_day TEXT, airs_time TEXT, airs_timezone TEXT, first_aired TEXT, aired_episodes INTEGER DEFAULT 0, cast_json TEXT, videos_json TEXT, images_json TEXT, seasons_json TEXT, votes INTEGER DEFAULT 0, detail_fetched_at TEXT, updated_at TEXT);
CREATE TABLE movies_cache (trakt_id INTEGER PRIMARY KEY, tmdb_id INTEGER, imdb_id TEXT, title TEXT NOT NULL, year INTEGER, released TEXT, runtime INTEGER DEFAULT 0, genres TEXT, overview TEXT, rating REAL DEFAULT 0, poster TEXT, thumb TEXT, list_slug TEXT, list_order INTEGER DEFAULT 0, listed_at TEXT, tagline TEXT, certification TEXT, country TEXT, language TEXT, trailer TEXT, homepage TEXT, fanart TEXT, logo TEXT, cast_json TEXT, videos_json TEXT, images_json TEXT, after_credits INTEGER DEFAULT 0, during_credits INTEGER DEFAULT 0, votes INTEGER DEFAULT 0, detail_fetched_at TEXT, updated_at TEXT);
DELETE FROM sqlite_sequence;
CREATE INDEX idx_games_estado ON games(estado);
CREATE INDEX idx_games_console ON games(console_pc);
CREATE INDEX idx_dates_played_game ON dates_played(game_id);
CREATE INDEX idx_dates_played_year ON dates_played(year);
CREATE UNIQUE INDEX idx_games_title ON games(title);
CREATE UNIQUE INDEX idx_dates_unique ON dates_played(game_id, year, fecha_inicio);
CREATE INDEX idx_steam_cache_name ON steam_cache(name);
CREATE INDEX idx_next_games_cache_date ON next_games_cache(release_date);
CREATE INDEX idx_series_watched_slug ON series_watched(trakt_slug);
CREATE INDEX idx_series_watched_year ON series_watched(year_watched);
CREATE INDEX idx_movies_cache_year ON movies_cache(year);
CREATE INDEX idx_movies_cache_list ON movies_cache(list_slug);
CREATE INDEX idx_movies_cache_title ON movies_cache(title);
